/**
 * cms-block-kind.js
 *
 * Watches the `kind` select inside each PageBlock inline row and shows only
 * the form rows that are relevant for the chosen block type.
 *
 * Scope: Django admin only (uses django.jQuery).
 * No model changes, no template edits, no SEO impact.
 * Degrades gracefully — if the script fails, all fields remain visible.
 */
(function ($) {
  'use strict';

  // ── Field-group selectors ────────────────────────────────────────────────
  // Each entry targets the `<div class="form-row field-X …">` generated by
  // Django admin for the corresponding tuple in PageBlockInline.fields.
  // Multi-field tuples (e.g. ("image", "image_alt")) get *both* class names
  // on the single row div, so targeting just the first one is enough.

  var HEADING = ['.field-heading_pl', '.field-heading_uk', '.field-heading_level'];
  var BODY    = ['.field-body_pl', '.field-body_uk'];

  var KIND_SHOW = {
    text:      HEADING.concat(BODY),
    image:     HEADING.concat(BODY).concat(['.field-image']),
    gallery:   ['.field-gallery_items_count'],
    video:     HEADING.concat(BODY).concat(['.field-video_embed_url']),
    cta:       HEADING.concat(BODY).concat(['.field-button_text']),
    form:      ['.field-form_kind'],
    countdown: ['.field-countdown_target'],
    reviews:   ['.field-reviews_limit'],
    related:   ['.field-related_strategy'],
    html:      BODY
  };

  // Every selector that is conditionally shown/hidden (union of all groups).
  var ALL_OPTIONAL = HEADING.concat(BODY).concat([
    '.field-image',
    '.field-video_embed_url',
    '.field-button_text',
    '.field-countdown_target',
    '.field-form_kind',
    '.field-reviews_limit',
    '.field-related_strategy',
    '.field-gallery_items_count'
  ]);

  // ── Core logic ───────────────────────────────────────────────────────────

  function applyKindVisibility(fieldsetEl) {
    var $fs   = $(fieldsetEl);
    var kind  = $fs.find('select[name$="-kind"]').val();
    var toShow = KIND_SHOW[kind];

    if (!kind || !toShow) {
      // No kind selected yet (new row) or unrecognised value → show everything
      // so the user can see all fields before choosing a type.
      $fs.find(ALL_OPTIONAL.join(',')).show();
      return;
    }

    $fs.find(ALL_OPTIONAL.join(',')).hide();
    $fs.find(toShow.join(',')).show();
  }

  function initFieldset(fieldsetEl) {
    applyKindVisibility(fieldsetEl);
    $(fieldsetEl)
      .find('select[name$="-kind"]')
      .on('change', function () {
        applyKindVisibility(fieldsetEl);
      });
  }

  // ── Bootstrap ────────────────────────────────────────────────────────────

  $(document).ready(function () {
    // Initialise all existing inline rows on page load.
    $('fieldset.cms-block-inline').each(function () {
      initFieldset(this);
    });

    // Initialise rows that Django admin adds dynamically via "Add another".
    $(document).on('formset:added', function (event, $row) {
      $row.find('fieldset.cms-block-inline').each(function () {
        initFieldset(this);
      });
    });
  });

}(django.jQuery));
